#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int X, Y;
        scanf("%d %d", &X, &Y);
        while (X > 0 && Y > 0 && X != Y) {
            if (X < Y) {
                Y -= X;
            } else {
                X -= Y;
            }
        }
        printf("%d\n", X + Y);
    }
    return 0;
}

