code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int X = sc.nextInt();
            int Y = sc.nextInt();
            while (X > 0 && Y > 0 && X != Y) {
                if (X < Y) {
                    Y -= X;
                } else {
                    X -= Y;
                }
            }
            System.out.println(X + Y);
        }
    }
}

