const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [X, Y] = readline().split(' ').map(Number);
    while (X > 0 && Y > 0 && X !== Y) {
        if (X < Y) {
            Y -= X;
        } else {
            X -= Y;
        }
    }
    console.log(X + Y);
}

